import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { executeQuery, fetchSchema, flushSession, QueryRequest } from './api';
import type { DatabaseSchema } from './api';
import SearchableDropdown from './SearchableDropdown';
import { Play as PlayIcon, Plus as PlusIcon, Edit2 as EditIcon, Trash2 as TrashIcon, X as XIcon, Clock } from 'lucide-react';

const DEFAULT_PAYLOAD = `{
  "username": "deep_testing",
  "city": "Gujarat",
  "family": [
      { "sister": "sis" },
      { "brother": "bro" }
  ]
}`;

const DEFAULT_UPDATES = `{
  "city": "Ahmedabad"
}`;

const KNOWN_SESSION_IDS = [
    'session_assignment_2',
    'session_test_01'
];

type Operation = 'read' | 'create' | 'update' | 'delete';

interface ResultTab {
    id: number;
    label: string;
    response: any;
    request: any;
    timestamp: Date;
}
let tabCounter = 0;

interface CrudPanelProps {
    onDataChanged?: () => void;
}

const CrudPanel: React.FC<CrudPanelProps> = ({ onDataChanged }) => {
    const [operation, setOperation] = useState<Operation>('read');
    const [schema, setSchema] = useState<DatabaseSchema>({});
    const [fetchingSchema, setFetchingSchema] = useState(true);

    const [table, setTable] = useState('chiral_data');
    const [sessionId, setSessionId] = useState('session_assignment_2');
    const [selectFields, setSelectFields] = useState<string>('*');
    const [filterField, setFilterField] = useState('session_id');
    const [filterOp, setFilterOp] = useState('eq');
    const [filterValue, setFilterValue] = useState('');
    const [limit, setLimit] = useState<number | string>(10);
    const [payloadJson, setPayloadJson] = useState(DEFAULT_PAYLOAD);
    const [updatesJson, setUpdatesJson] = useState(DEFAULT_UPDATES);

    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const [resultTabs, setResultTabs] = useState<ResultTab[]>([]);
    const [activeTabId, setActiveTabId] = useState<number | null>(null);
    const [sidebarWidth, setSidebarWidth] = useState(380);

    useEffect(() => {
        let mounted = true;
        fetchSchema().then(liveSchema => {
            if (mounted) {
                setSchema(liveSchema);
                setFetchingSchema(false);
            }
        }).catch(err => {
            if (mounted) {
                setError("Failed to connect to backend: " + err.message);
                setFetchingSchema(false);
            }
        });
        return () => { mounted = false; };
    }, []);

    const tableList = useMemo(() => Object.keys(schema), [schema]);
    const columnOptions = useMemo(() => {
        if (!schema[table]) return ['*'];
        return ['*', ...schema[table].columns.map(c => c.name)];
    }, [schema, table]);

    useEffect(() => {
        if (!fetchingSchema && schema[table]) {
            const firstValidCol = schema[table].columns[0]?.name || '*';
            setFilterField(table === 'chiral_data' ? 'session_id' : firstValidCol);
            setFilterValue('');
        }
    }, [table, schema, fetchingSchema]);

    const startResize = useCallback((mouseDownEvent: React.MouseEvent) => {
        mouseDownEvent.preventDefault();
        const startX = mouseDownEvent.clientX;
        const startWidth = sidebarWidth;

        const onMouseMove = (moveEvent: MouseEvent) => {
            let newWidth = startWidth + (moveEvent.clientX - startX);
            if (newWidth < 250) newWidth = 250;
            if (newWidth > 800) newWidth = 800;
            setSidebarWidth(newWidth);
        };
        const onMouseUp = () => {
            document.removeEventListener('mousemove', onMouseMove);
            document.removeEventListener('mouseup', onMouseUp);
        };
        document.addEventListener('mousemove', onMouseMove);
        document.addEventListener('mouseup', onMouseUp);
    }, [sidebarWidth]);

    const executeOp = useCallback(async () => {
        setError(null);
        setLoading(true);

        const req: QueryRequest = { operation, table };
        if (sessionId) req.session_id = sessionId;

        if (operation === 'read') {
            if (selectFields && selectFields !== '*') {
                req.select = selectFields.split(',').map(s => s.trim()).filter(Boolean);
            }
            if (limit) {
                req.limit = typeof limit === 'string' ? parseInt(limit, 10) : limit;
            }
        }

        if (filterField && filterValue && filterField !== '*') {
            let val: any = filterValue;
            if (!isNaN(Number(val)) && val.trim() !== '') {
                val = Number(val);
            } else if (val.toLowerCase() === 'true') {
                val = true;
            } else if (val.toLowerCase() === 'false') {
                val = false;
            }
            req.filters = [{ field: filterField, operator: filterOp, value: val }];
        }

        if (operation === 'create') {
            try {
                req.payload = JSON.parse(payloadJson);
            } catch (e) {
                setError('Invalid JSON payload for CREATE');
                setLoading(false);
                return;
            }
        }

        if (operation === 'update') {
            try {
                req.updates = JSON.parse(updatesJson);
            } catch (e) {
                setError('Invalid JSON payload for UPDATE');
                setLoading(false);
                return;
            }
        }

        try {
            const response = await executeQuery(req);
            const tabLabel = `${operation.toUpperCase()} ${table.split('_').slice(0, 2).join('_')}`;

            setResultTabs(prev => {
                const existingIdx = prev.findIndex(t => t.label === tabLabel);
                if (existingIdx >= 0) {
                    const updated = [...prev];
                    updated[existingIdx] = {
                        ...updated[existingIdx],
                        response,
                        request: req,
                        timestamp: new Date()
                    };
                    setTimeout(() => setActiveTabId(updated[existingIdx].id), 0);
                    return updated;
                } else {
                    const newTab: ResultTab = {
                        id: ++tabCounter,
                        label: tabLabel,
                        response,
                        request: req,
                        timestamp: new Date(),
                    };
                    setTimeout(() => setActiveTabId(newTab.id), 0);
                    return [...prev, newTab];
                }
            });

            if (operation !== 'read' && onDataChanged) {
                onDataChanged();
                fetchSchema().then(setSchema).catch(console.error);
            }
        } catch (err: unknown) {
            const msg = err instanceof Error ? err.message : 'Unknown error';
            setError(msg);
        } finally {
            setLoading(false);
        }
    }, [operation, table, sessionId, selectFields, filterField, filterOp, filterValue, payloadJson, updatesJson, limit, onDataChanged]);

    const activeTab = resultTabs.find(t => t.id === activeTabId);

    return (
        <div className="crud-panel">
            <div className="crud-form-container" style={{ width: sidebarWidth }}>
                <div className="crud-resizer" onMouseDown={startResize} />
                <div className="crud-form">
                    <h2 className="crud-title">Query Executor</h2>

                    <div className="crud-row">
                        <label>Operation</label>
                        <div className="crud-op-selector">
                            {(['read', 'create', 'update', 'delete'] as Operation[]).map(op => (
                                <button
                                    key={op}
                                    className={`crud-op-btn ${operation === op ? 'active' : ''} crud-op-${op}`}
                                    onClick={() => setOperation(op)}
                                >
                                    {op === 'read' && <PlayIcon />}
                                    {op === 'create' && <PlusIcon />}
                                    {op === 'update' && <EditIcon />}
                                    {op === 'delete' && <TrashIcon />}
                                    {op.toUpperCase()}
                                </button>
                            ))}
                        </div>
                    </div>

                    <div className="crud-row">
                        <label>Table</label>
                        {fetchingSchema ? (
                            <div className="crud-input" style={{ opacity: 0.5 }}>Loading tables...</div>
                        ) : (
                            <SearchableDropdown
                                options={tableList.length > 0 ? tableList : ['chiral_data', 'session_metadata']}
                                value={table}
                                onChange={setTable}
                                placeholder="Search tables..."
                                allowFreeText
                            />
                        )}
                    </div>

                    <div className="crud-row">
                        <label>Session ID</label>
                        <div style={{ display: 'flex', gap: '8px', flex: 1 }}>
                            <div style={{ flex: 1 }}>
                                <SearchableDropdown
                                    options={KNOWN_SESSION_IDS}
                                    value={sessionId}
                                    onChange={setSessionId}
                                    placeholder="Type or select session..."
                                    allowFreeText
                                />
                            </div>
                            <button
                                className="crud-submit-btn"
                                style={{ background: '#3b82f6', flex: '0 0 auto', padding: '0 16px', borderRadius: '6px' }}
                                onClick={async () => {
                                    if (!sessionId) return;
                                    setLoading(true);
                                    try {
                                        await flushSession(sessionId);
                                        if (operation === 'read') executeOp();
                                        fetchSchema().then(setSchema).catch(console.error);
                                    } catch (err: unknown) {
                                        setError(err instanceof Error ? err.message : 'Flush failed');
                                    } finally {
                                        setLoading(false);
                                    }
                                }}
                                disabled={!sessionId || loading}
                                title="Flush queued staging data into main tables"
                            >
                                Flush API
                            </button>
                        </div>
                    </div>

                    {operation === 'read' && (
                        <>
                            <div className="crud-row">
                                <label>Select Fields</label>
                                <SearchableDropdown
                                    options={columnOptions}
                                    value={selectFields}
                                    onChange={setSelectFields}
                                    placeholder="Type column names (comma separated)..."
                                    allowFreeText
                                    multiple
                                />
                            </div>
                            <div className="crud-row">
                                <label>Limit</label>
                                <input className="crud-input" type="number" value={limit} onChange={e => setLimit(e.target.value)} />
                            </div>
                        </>
                    )}

                    <div className="crud-row">
                        <label>Filter</label>
                        <div className="crud-filter-row">
                            <SearchableDropdown
                                options={columnOptions.filter(c => c !== '*')}
                                value={filterField}
                                onChange={setFilterField}
                                placeholder="field"
                                allowFreeText
                            />
                            <select value={filterOp} onChange={e => setFilterOp(e.target.value)} className="crud-select crud-select-sm">
                                <option value="eq">=</option>
                                <option value="neq">≠</option>
                                <option value="gt">&gt;</option>
                                <option value="lt">&lt;</option>
                                <option value="gte">≥</option>
                                <option value="lte">≤</option>
                                <option value="like">LIKE</option>
                            </select>
                            <input className="crud-input crud-input-sm" value={filterValue} onChange={e => setFilterValue(e.target.value)} placeholder="value" />
                        </div>
                    </div>

                    {operation === 'create' && (
                        <div className="crud-row">
                            <label>Payload (JSON)</label>
                            <textarea
                                className="crud-textarea"
                                value={payloadJson}
                                onChange={e => setPayloadJson(e.target.value)}
                            />
                        </div>
                    )}

                    {operation === 'update' && (
                        <div className="crud-row">
                            <label>Updates (JSON)</label>
                            <textarea
                                className="crud-textarea"
                                value={updatesJson}
                                onChange={e => setUpdatesJson(e.target.value)}
                            />
                        </div>
                    )}

                    <button className="crud-submit-btn" onClick={executeOp} disabled={loading}>
                        {loading ? 'Executing...' : (
                            <>
                                {operation === 'read' && <PlayIcon />}
                                {operation === 'create' && <PlusIcon />}
                                {operation === 'update' && <EditIcon />}
                                {operation === 'delete' && <TrashIcon />}
                                Execute {operation.toUpperCase()}
                            </>
                        )}
                    </button>
                </div>
            </div>

            <div className="crud-results">
                {error && (
                    <div className="crud-error-banner">
                        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                            <circle cx="12" cy="12" r="10" />
                            <line x1="12" y1="8" x2="12" y2="12" />
                            <line x1="12" y1="16" x2="12.01" y2="16" />
                        </svg>
                        {error}
                        <button className="crud-error-dismiss" onClick={() => setError(null)}><XIcon size={16} /></button>
                    </div>
                )}

                <div className="crud-tabs-header">
                    {resultTabs.length === 0 ? (
                        <div className="crud-tabs-empty">No results yet. Run a query.</div>
                    ) : (
                        resultTabs.map(tab => (
                            <div
                                key={tab.id}
                                className={`crud-tab ${activeTabId === tab.id ? 'active' : ''}`}
                                onClick={() => setActiveTabId(tab.id)}
                            >
                                <span className={`crud-tab-indicator op-${tab.label.split(' ')[0].toLowerCase()}`} />
                                {tab.label}
                                <span className="crud-tab-close" onClick={(e) => {
                                    e.stopPropagation();
                                    setResultTabs(prev => prev.filter(t => t.id !== tab.id));
                                    if (activeTabId === tab.id) {
                                        setActiveTabId(resultTabs.length > 1 ? resultTabs[resultTabs.length - 2].id : null);
                                    }
                                }}>
                                    <XIcon size={14} />
                                </span>
                            </div>
                        ))
                    )}
                </div>

                {activeTab ? (
                    <div className="crud-tab-content">
                        <div className="crud-tab-meta">
                            <Clock size={14} />
                            <span>{activeTab.timestamp.toLocaleTimeString()}</span>
                            {activeTab.response.row_count !== undefined && (
                                <span className="crud-badge count-badge">{activeTab.response.row_count} rows</span>
                            )}
                            {activeTab.response.affected_rows !== undefined && (
                                <span className="crud-badge affected-badge">{activeTab.response.affected_rows} updated</span>
                            )}
                            {activeTab.response.mode === 'queued_async' && (
                                <span className="crud-badge async-badge">Queued Async</span>
                            )}
                        </div>

                        <div className="crud-code-block">
                            <div className="crud-code-header">SQL EXECUTED</div>
                            <pre><code>{activeTab.response.sql || '-- No SQL executed (handled via background staging queue)'}</code></pre>
                        </div>

                        {activeTab.response.rows && activeTab.response.rows.length > 0 && (
                            <div className="crud-table-container">
                                <table>
                                    <thead>
                                        <tr>
                                            {Object.keys(activeTab.response.rows[0]).map(k => (
                                                <th key={k}>{k}</th>
                                            ))}
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {activeTab.response.rows.map((row: any, i: number) => (
                                            <tr key={i}>
                                                {Object.keys(activeTab.response.rows[0]).map(k => (
                                                    <td key={k}>
                                                        {typeof row[k] === 'object' ? JSON.stringify(row[k]) : String(row[k])}
                                                    </td>
                                                ))}
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        )}

                        {(activeTab.response.params && Object.keys(activeTab.response.params).length > 0) && (
                            <div className="crud-code-block" style={{ marginTop: '20px' }}>
                                <div className="crud-code-header">BIND PARAMETERS / METADATA</div>
                                <pre><code>{JSON.stringify(activeTab.response.params, null, 2)}</code></pre>
                            </div>
                        )}
                    </div>
                ) : (
                    <div className="crud-tab-content-empty">
                        Execute an operation to see results.
                    </div>
                )}
            </div>
        </div>
    );
};

export default CrudPanel;
